import { Component, computed, signal, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Task, TaskFilter } from '../../core/services/task.service';

@Component({
  selector: 'app-tasks',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './tasks.component.html',
  styleUrl: './tasks.component.css',
})
export class TasksComponent implements OnInit {
  // Data contract: mock data lives in a signal<Task[]> so mockup_cleaner can empty it
  // and service_agent can wire it to TaskService in ngOnInit().
  tasks = signal<Task[]>([
    { id: '1', title: 'Draft the Q3 roadmap', done: false, createdAt: '2026-07-01T09:00:00Z' },
    { id: '2', title: 'Review pull request #482', done: false, createdAt: '2026-07-02T11:30:00Z' },
    { id: '3', title: 'Reply to onboarding emails', done: true, createdAt: '2026-07-02T14:15:00Z' },
    { id: '4', title: 'Prepare demo for stakeholders', done: false, createdAt: '2026-07-03T08:45:00Z' },
    { id: '5', title: 'Update dependency versions', done: true, createdAt: '2026-07-03T16:20:00Z' },
  ]);

  filter = signal<TaskFilter>('all');
  newTitle = '';

  readonly filters: { key: TaskFilter; label: string }[] = [
    { key: 'all', label: 'All' },
    { key: 'active', label: 'Active' },
    { key: 'done', label: 'Done' },
  ];

  readonly visibleTasks = computed(() => {
    const f = this.filter();
    return this.tasks().filter((t) =>
      f === 'active' ? !t.done : f === 'done' ? t.done : true,
    );
  });

  readonly activeCount = computed(() => this.tasks().filter((t) => !t.done).length);

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private auth: AuthService,
  ) {}

  ngOnInit(): void {
    // Restore the filter from the URL so /tasks?filter=done is deep-linkable.
    this.route.queryParamMap.subscribe((params) => {
      const f = params.get('filter') as TaskFilter | null;
      this.filter.set(f === 'active' || f === 'done' ? f : 'all');
    });
  }

  setFilter(f: TaskFilter): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { filter: f },
      queryParamsHandling: 'merge',
    });
  }

  addTask(): void {
    const title = this.newTitle.trim();
    if (!title) return;
    const task: Task = {
      id: `local-${this.tasks().length + 1}-${title.length}`,
      title,
      done: false,
      createdAt: '2026-07-07T00:00:00Z',
    };
    this.tasks.update((list) => [task, ...list]);
    this.newTitle = '';
  }

  toggleDone(task: Task): void {
    this.tasks.update((list) =>
      list.map((t) => (t.id === task.id ? { ...t, done: !t.done } : t)),
    );
  }

  deleteTask(task: Task): void {
    this.tasks.update((list) => list.filter((t) => t.id !== task.id));
  }

  logout(): void {
    this.auth.logout();
  }
}
